 1	import * as React from 'react';
 2	import { BackendType } from '@odf/mco/constants';
 3	import { useCustomTranslation } from '@odf/shared';
 4	import {
 5	  Card,
 6	  CardFooter,
 7	  CardHeader,
 8	  CardTitle,
 9	} from '@patternfly/react-core';
10	
11	type BackendOptionProps = {
12	  backendType: BackendType;
13	  clusterNames?: string[];
14	  isSelected?: boolean;
15	  onSelect: (selected: BackendType) => void;
16	};
17	
18	export const BackendOptionCard: React.FC<BackendOptionProps> = ({
19	  backendType,
20	  clusterNames,
21	  isSelected,
22	  onSelect,
23	}) => {
24	  const onChange = (_event: React.FormEvent<HTMLInputElement>) => {
25	    onSelect(backendType);
26	  };
27	
28	  const { t } = useCustomTranslation();
29	
30	  const renderSelectedClusters = () => {
31	    if (!clusterNames || clusterNames.length === 0) {
32	      return t('No clusters selected');
33	    }
34	
35	    const combinedNames = clusterNames.join(', ');
36	    return t('Selected Clusters: {{clusters}}', {
37	      clusters: combinedNames,
38	    });
39	  };
40	
41	  return (
42	    <Card
43	      id={`selectable-action-${backendType}`}
44	      isSelectable
45	      onClick={() => onSelect(backendType)}
46	      isSelected={isSelected}
47	    >
48	      <CardHeader
49	        selectableActions={{
50	          selectableActionId: `selectable-action-${backendType}`,
51	          selectableActionAriaLabelledby: `selectable-action-${backendType}`,
52	          name: 'single-selectable-storage-backend',
53	          variant: 'single',
54	          onChange,
55	          hasNoOffset: true,
56	        }}
57	      >
58	        <CardTitle>{backendType}</CardTitle>
59	      </CardHeader>
60	      <CardFooter>{renderSelectedClusters()}</CardFooter>
61	    </Card>
62	  );
63	};

